// === Validate & Sanitize v4.0 ===
// Добавлено: niche_cluster, priority_engines, project_phase, cms

const body = $input.first().json.body || $input.first().json;
const raw_niche = body.niche || '';
const raw_city = body.city || '';
const project_id = body.project_id || '';
const batch_size = body.batch_size || 3;

if (!raw_niche) throw new Error('Поле "niche" обязательно');
if (!raw_city) throw new Error('Поле "city" обязательно');
if (!project_id) throw new Error('Поле "project_id" обязательно');

// Формат project_id: niche_city_NNN
if (!/^[a-z0-9_]+$/.test(project_id)) throw new Error('project_id: только a-z, 0-9, _ (формат: niche_city_NNN)');

// Sanitize inputs
const sanitize = (s) => s.replace(/[\n\r\t`{}\[\]<>|;$]/g, '').substring(0, 100).trim();
const niche = sanitize(raw_niche);
const city = sanitize(raw_city);

// v4.0: Multi-project + niche_cluster
const validClusters = ['commercial_local', 'commercial_national', 'ecom', 'saas', 'info'];
const niche_cluster = validClusters.includes(body.niche_cluster) ? body.niche_cluster : 'commercial_local';
const priority_engines = ['yandex', 'google', 'both'].includes(body.priority_engines) ? body.priority_engines : 'both';
const project_phase = ['setup', 'growth', 'maintenance', 'recovery'].includes(body.project_phase) ? body.project_phase : 'setup';
const cms = body.cms || 'unknown';

const embed_query = `${niche} ${city} техническое задание контент страница секции разделы UX CTA SEO AEO E-E-A-T 2026`;

return [{ json: {
  niche, city, project_id,
  niche_cluster, priority_engines, project_phase, cms,
  batch_size: Math.min(Math.max(batch_size, 1), 5),
  embed_query,
  workflow_version: 'v4.0_pro',
  started_at: new Date().toISOString()
}}];

// === Merge RAG Context v4.0 ===
// Добавлено: контекст конкурентов (CI), коммерческие факторы [Я], niche_cluster

const validate = $('Validate & Sanitize v4').first().json;
let personaCtx = '';
try {
  const personas = $('RAG Personas').first().json.result || [];
  if (personas.length) {
    personaCtx = '=== ЦЕЛЕВАЯ АУДИТОРИЯ ===\n';
    personas.forEach((r, i) => {
      const p = r.payload || {};
      personaCtx += `Персона ${i+1}: ${p.persona_name || 'N/A'}`;
      if (p.pain_points) personaCtx += ` | Боли: ${typeof p.pain_points === 'string' ? p.pain_points : JSON.stringify(p.pain_points).substring(0, 300)}`;
      if (p.intent_type) personaCtx += ` | Интент: ${p.intent_type}`;
      if (p.decision_factors) personaCtx += ` | Решающие факторы: ${p.decision_factors}`;
      personaCtx += '\n';
    });
  }
} catch(e) {}

let structCtx = '';
try {
  const structs = $('RAG Structures').first().json.result || [];
  if (structs.length) {
    structCtx = '\n=== ЛУЧШИЕ СТРУКТУРЫ СТРАНИЦ (RAG) ===\n';
    structs.forEach((r, i) => {
      const p = r.payload || {};
      structCtx += `Пример ${i+1}: ${p.page_type || ''} — ${p.section_count || '?'} секций, ${p.word_count || '?'} слов`;
      if (p.sections_summary) structCtx += ` | Секции: ${p.sections_summary}`;
      if (p.schema_types) structCtx += ` | Schema: ${p.schema_types}`;
      structCtx += '\n';
    });
  }
} catch(e) {}

let historyCtx = '';
try {
  const history = $('RAG Briefs History').first().json.result || [];
  if (history.length) {
    historyCtx = '\n=== ПРЕДЫДУЩИЕ ТЗ (контекст) ===\n';
    history.forEach((r, i) => {
      const p = r.payload || {};
      historyCtx += `ТЗ ${i+1}: ${p.page_slug || ''} — QC: ${p.qc_score || '?'}/100, ${p.sections_count || '?'} секций`;
      if (p.ml_score) historyCtx += `, ML: ${p.ml_score}`;
      historyCtx += '\n';
    });
  }
} catch(e) {}

// v4.0: Competitive Intelligence контекст
let competitorCtx = '';
try {
  const competitors = $('RAG Competitors').first().json.result || [];
  if (competitors.length) {
    competitorCtx = '\n=== КОНКУРЕНТЫ (CI) ===\n';
    competitors.forEach((r, i) => {
      const p = r.payload || {};
      competitorCtx += `Конкурент ${i+1}: ${p.domain || '?'}`;
      if (p.top_sections) competitorCtx += ` | ТОП-секции: ${p.top_sections}`;
      if (p.avg_word_count) competitorCtx += ` | Слов: ${p.avg_word_count}`;
      if (p.schema_types) competitorCtx += ` | Schema: ${p.schema_types}`;
      if (p.eeat_signals) competitorCtx += ` | E-E-A-T: ${p.eeat_signals}`;
      competitorCtx += '\n';
    });
  }
} catch(e) {}

// v4.0: Коммерческие факторы [Я]
let kfCtx = '';
try {
  const kfData = $('Fetch KF Data').first().json.list || [];
  if (kfData.length) {
    kfCtx = '\n=== КОММЕРЧЕСКИЕ ФАКТОРЫ [Я] ===\n';
    kfData.forEach(kf => {
      kfCtx += `${kf.factor_name || ''}: ${kf.status || ''} | Приоритет: ${kf.priority || ''}\n`;
    });
  }
} catch(e) {}

const fullContext = (personaCtx + structCtx + historyCtx + competitorCtx + kfCtx) || 'Нет RAG-данных.';

return [{ json: {
  rag_context: fullContext,
  rag_sources: {
    personas: personaCtx ? 'yes' : 'no',
    structures: structCtx ? 'yes' : 'no',
    history: historyCtx ? 'yes' : 'no',
    competitors: competitorCtx ? 'yes' : 'no',
    kf: kfCtx ? 'yes' : 'no'
  }
}}];

// === Parse & Split Batches v4.0 ===
// Добавлено: приоритизация, cannibalization check, niche_cluster

const structResponse = $('Fetch Page Structures').first().json;
const linksResponse = $('Fetch Internal Links').first().json;
const validate = $('Validate & Sanitize v4').first().json;
const ragInfo = $('Merge RAG Context v2').first().json;

const pages = structResponse.list || [];
if (pages.length === 0) throw new Error('Нет структур страниц для project_id: ' + validate.project_id + '. Сначала запустите Шаг 04.');

const links = (linksResponse.list || []);
const linksMap = {};
links.forEach(l => {
  const from = l.from_url || '';
  if (!linksMap[from]) linksMap[from] = [];
  linksMap[from].push({ to: l.to_url, anchor: l.anchor });
});

// v4.0: Cannibalization check — выявляем пересечения ключевых слов
const keywordMap = {};
const cannibalizationWarnings = [];
pages.forEach(p => {
  const kw = (p.main_keyword || '').toLowerCase().trim();
  if (kw) {
    if (keywordMap[kw]) {
      cannibalizationWarnings.push(`⚠ Каннибализация: "${kw}" используется на ${keywordMap[kw]} И ${p.recommended_url}`);
    }
    keywordMap[kw] = p.recommended_url;
  }
});

if (cannibalizationWarnings.length > 0) {
  console.log('[Step08 v4.0] CANNIBALIZATION DETECTED:', cannibalizationWarnings.join('; '));
}

// v4.0: Приоритизация — high priority страницы первые
const priorityOrder = { high: 0, medium: 1, low: 2 };
const sortedPages = [...pages].sort((a, b) => {
  const pa = priorityOrder[a.implementation_priority || 'medium'] ?? 1;
  const pb = priorityOrder[b.implementation_priority || 'medium'] ?? 1;
  return pa - pb;
});

const BATCH_SIZE = validate.batch_size || 3;
const batches = [];
for (let i = 0; i < sortedPages.length; i += BATCH_SIZE) {
  const batch = sortedPages.slice(i, i + BATCH_SIZE);
  const batchSummary = batch.map((p, j) => {
    const pageLinks = linksMap[p.recommended_url] || [];
    let blocks = [];
    try { blocks = typeof p.blocks === 'string' ? JSON.parse(p.blocks) : (p.blocks || []); } catch(e) {}
    return `${i+j+1}. [${(p.page_type||'commercial').toUpperCase()}] ${p.cluster_name||''}
   URL: ${p.recommended_url||''}
   Ключ: ${p.main_keyword||''}
   H1: ${p.h1_template||''}
   Title: ${p.title_template||''}
   Description: ${p.description_template||''}
   Блоков: ${blocks.length}, Слов: ${p.total_word_count||0}
   Блоки: ${blocks.map(b => b.block_name).join(', ')}
   Ссылки: ${pageLinks.length > 0 ? pageLinks.map(l => l.anchor + ' → ' + l.to).join('; ') : 'нет'}`;
  }).join('\n\n');

  batches.push({
    batch_index: Math.floor(i / BATCH_SIZE) + 1,
    total_batches: Math.ceil(sortedPages.length / BATCH_SIZE),
    batch_pages: batch,
    pages_summary: batchSummary,
    batch_size: batch.length,
    niche: validate.niche,
    city: validate.city,
    project_id: validate.project_id,
    niche_cluster: validate.niche_cluster,
    priority_engines: validate.priority_engines,
    project_phase: validate.project_phase,
    total_pages: sortedPages.length,
    rag_context: ragInfo.rag_context,
    cannibalization_warnings: cannibalizationWarnings
  });
}

return batches.map(b => ({ json: b }));

// === Parse & Validate Briefs v4.0 ===
// Добавлено: qc_score расчёт, schema_types, aeo_readiness, engine_tag

const batchInfo = $('Build Dynamic Prompt v4').first().json;
let rawContent = '';
let tokensUsed = 0;
let llm_source = 'groq';

try {
  const groqResp = $('Groq Page Briefs').first().json;
  if (!groqResp.error && groqResp.choices) {
    rawContent = groqResp.choices[0]?.message?.content || '';
    tokensUsed = groqResp.usage?.total_tokens || 0;
  }
} catch(e) {}

if (!rawContent) {
  try {
    const ollamaResp = $('Fallback Ollama').first().json;
    rawContent = ollamaResp.message?.content || '';
    llm_source = 'ollama_fallback';
  } catch(e) {}
}

if (!rawContent) {
  return [{ json: { batch_index: batchInfo.batch_index, briefs_count: 0, nocodb_payload: [], error: 'Both Groq and Ollama failed', groq_tokens: 0, total_batches: batchInfo.total_batches, llm_source: 'none' }}];
}

let cleanJson = rawContent.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleanJson);
} catch(err) {
  try { const m = cleanJson.match(/\{[\s\S]+\}/); if(m) parsed = JSON.parse(m[0]); } catch(e) {}
  if (!parsed) {
    return [{ json: { batch_index: batchInfo.batch_index, briefs_count: 0, nocodb_payload: [], error: 'Invalid JSON: ' + cleanJson.substring(0,200), groq_tokens: tokensUsed, total_batches: batchInfo.total_batches, llm_source }}];
  }
}

if (Array.isArray(parsed)) parsed = { page_briefs: parsed };
else if (parsed && !parsed.page_briefs && parsed.page_slug) parsed = { page_briefs: [parsed] };

const validPageTypes = ['commercial', 'informational', 'navigation', 'landing'];
const briefs = (parsed.page_briefs || []).map((b, idx) => {
  const sections = Array.isArray(b.sections_json) ? b.sections_json : [];
  const sectionTypes = sections.map(s => s.section_type || '');

  // v4.0: Content Quality Score (0-100)
  let qc_score = 0;
  // Слой 1: Релевантность (макс 20)
  const keywordCoverage = sections.reduce((s, sec) => s + (sec.keywords?.length || 0), 0);
  qc_score += Math.min(keywordCoverage * 2, 20);
  // Слой 2: Читаемость (макс 20)
  const avgWords = sections.reduce((s, sec) => s + (sec.word_count || 0), 0) / Math.max(sections.length, 1);
  if (avgWords >= 100 && avgWords <= 400) qc_score += 20;
  else if (avgWords >= 50) qc_score += 10;
  // Слой 3: E-E-A-T (макс 20)
  const eeatCount = sections.filter(s => s.eeat_signals && s.eeat_signals.length > 0).length;
  qc_score += Math.min(Math.round(eeatCount / Math.max(sections.length, 1) * 20), 20);
  // Слой 4: AEO/GEO (макс 20)
  const aeoCount = sections.filter(s => s.aeo_question).length;
  const hasFAQ = sectionTypes.includes('faq');
  qc_score += hasFAQ ? 10 : 0;
  qc_score += Math.min(aeoCount * 2, 10);
  // Слой 5: Humanization (макс 20)
  const totalWords = b.word_count_target || sections.reduce((s, sec) => s + (sec.word_count || 0), 0);
  if (totalWords >= 2000) qc_score += 10;
  if (sections.length >= 10) qc_score += 10;

  return {
    project_id: batchInfo.project_id,
    niche: batchInfo.niche,
    city: batchInfo.city,
    niche_cluster: batchInfo.niche_cluster,
    priority_engines: batchInfo.priority_engines,
    page_slug: b.page_slug || '',
    page_type: validPageTypes.includes(b.page_type) ? b.page_type : 'commercial',
    h1: b.h1 || '',
    meta_title: (b.meta_title || '').substring(0, 60),
    meta_description: (b.meta_description || '').substring(0, 160),
    schema_types: JSON.stringify(b.schema_types || ['FAQPage']),
    sections_json: JSON.stringify(sections),
    sections_count: sections.length,
    cta_blocks: b.cta_blocks || sections.filter(s => s.cta_text).length || 0,
    word_count_target: totalWords,
    implementation_priority: b.implementation_priority || 'medium',
    top3_quick_wins: JSON.stringify(b.top3_quick_wins || []),
    content_quality_notes: b.content_quality_notes || '',
    aeo_readiness: b.aeo_readiness || 0,
    has_hero: sectionTypes.includes('hero'),
    has_faq: sectionTypes.includes('faq'),
    has_reviews: sectionTypes.includes('reviews'),
    has_pricing: sectionTypes.includes('pricing'),
    has_cta: sectionTypes.includes('cta'),
    has_speakable: sectionTypes.includes('speakable'),
    has_eeat_signals: eeatCount > 0,
    status: 'ready',
    qc_score,
    llm_source,
    version: 'v4.0_pro',
    created_at: new Date().toISOString()
  };
});

return [{ json: {
  batch_index: batchInfo.batch_index,
  total_batches: batchInfo.total_batches,
  briefs_count: briefs.length,
  nocodb_payload: briefs,
  groq_tokens: tokensUsed,
  llm_source,
  error: null
}}];

// === Quality Gate v2 — Content Quality Stack 5 слоёв ===

const d = $input.first().json;
if (d.briefs_count === 0 || d.error) {
  return [{ json: { ...d, qc_passed: false, qc_reason: d.error || 'No briefs generated' }}];
}

const issues = [];
const layerScores = { relevance: 0, readability: 0, eeat: 0, aeo: 0, humanization: 0 };
let totalQC = 0;

d.nocodb_payload.forEach((brief, idx) => {
  const sections = JSON.parse(brief.sections_json || '[]');
  const slug = brief.page_slug;

  // КРИТИЧЕСКИЕ ПРОВЕРКИ
  if (sections.length < 8) issues.push(`[КРИТИЧНО] ${slug}: ${sections.length} секций (мин. 8)`);
  if (brief.word_count_target < 1500) issues.push(`[КРИТИЧНО] ${slug}: ${brief.word_count_target} слов (мин. 1500)`);
  if (!brief.h1) issues.push(`[КРИТИЧНО] ${slug}: отсутствует h1`);
  if (!brief.meta_title) issues.push(`[КРИТИЧНО] ${slug}: отсутствует meta_title`);
  if (brief.meta_title && brief.meta_title.length > 60) issues.push(`[ВЫСОКИЙ] ${slug}: meta_title ${brief.meta_title.length} символов (макс. 60)`);
  if (brief.meta_description && brief.meta_description.length > 160) issues.push(`[ВЫСОКИЙ] ${slug}: meta_description ${brief.meta_description.length} символов (макс. 160)`);

  // Слой 1: Релевантность
  const totalKeywords = sections.reduce((s, sec) => s + (sec.keywords?.length || 0), 0);
  if (totalKeywords < 10) issues.push(`[СРЕДНИЙ] ${slug}: мало ключей (${totalKeywords}, мин. 10)`);

  // Слой 2: Читаемость
  const sectionsWithH2 = sections.filter(s => s.h2).length;
  if (sectionsWithH2 < sections.length * 0.8) issues.push(`[СРЕДНИЙ] ${slug}: ${sectionsWithH2}/${sections.length} секций с H2`);

  // Слой 3: E-E-A-T
  const eeatSections = sections.filter(s => s.eeat_signals && s.eeat_signals.length > 0).length;
  if (eeatSections < 3) issues.push(`[ВЫСОКИЙ] ${slug}: мало E-E-A-T сигналов (${eeatSections} секций)`);

  // Слой 4: AEO/GEO
  if (!brief.has_faq) issues.push(`[ВЫСОКИЙ] ${slug}: нет FAQ секции (AEO обязательно)`);
  const aeoQuestions = sections.filter(s => s.aeo_question).length;
  if (aeoQuestions < 3) issues.push(`[СРЕДНИЙ] ${slug}: мало AEO-вопросов (${aeoQuestions}, мин. 3)`);

  // Слой 5: Humanization
  if (brief.cta_blocks < 2) issues.push(`[СРЕДНИЙ] ${slug}: мало CTA (${brief.cta_blocks}, мин. 2)`);

  totalQC += brief.qc_score;
});

const avgQC = Math.round(totalQC / Math.max(d.briefs_count, 1));
const criticalIssues = issues.filter(i => i.includes('[КРИТИЧНО]'));
const qc_passed = criticalIssues.length === 0 && avgQC >= 40;

return [{ json: {
  ...d,
  qc_passed,
  qc_issues: issues,
  qc_critical_count: criticalIssues.length,
  qc_avg_score: avgQC,
  qc_stats: {
    avg_sections: Math.round(d.nocodb_payload.reduce((s, b) => s + JSON.parse(b.sections_json || '[]').length, 0) / d.briefs_count * 10) / 10,
    avg_words: Math.round(d.nocodb_payload.reduce((s, b) => s + b.word_count_target, 0) / d.briefs_count),
    avg_qc_score: avgQC
  }
}}];

// === Extract ML Features v4.0 ===
// Добавлено: aeo_ready, schema_count, engine_tags, kf_sections

const d = $('Quality Gate v2').first().json;
const features = d.nocodb_payload.map(brief => {
  const sections = JSON.parse(brief.sections_json || '[]');
  const sectionTypes = sections.map(s => s.section_type || '');
  const engineTags = sections.map(s => s.engine_tag || 'ОБА');
  const schemaTypes = JSON.parse(brief.schema_types || '[]');

  return {
    page_slug: brief.page_slug,
    page_type: brief.page_type,
    niche_cluster: brief.niche_cluster,
    section_count: sections.length,
    has_hero: sectionTypes.includes('hero') ? 1 : 0,
    has_faq: sectionTypes.includes('faq') ? 1 : 0,
    has_reviews: sectionTypes.includes('reviews') ? 1 : 0,
    has_pricing: sectionTypes.includes('pricing') ? 1 : 0,
    has_cta: sectionTypes.includes('cta') ? 1 : 0,
    has_comparison: sectionTypes.includes('comparison') ? 1 : 0,
    has_cases: sectionTypes.includes('cases') ? 1 : 0,
    has_trust: sectionTypes.includes('trust') ? 1 : 0,
    has_speakable: sectionTypes.includes('speakable') ? 1 : 0,
    has_eeat: brief.has_eeat_signals ? 1 : 0,
    word_count: brief.word_count_target,
    cta_count: brief.cta_blocks,
    h2_count: sections.filter(s => s.h2).length,
    avg_section_words: Math.round(brief.word_count_target / Math.max(sections.length, 1)),
    keyword_density: sections.reduce((s, sec) => s + (sec.keywords?.length || 0), 0),
    aeo_questions: sections.filter(s => s.aeo_question).length,
    schema_count: schemaTypes.length,
    ya_sections: engineTags.filter(t => t === 'Я').length,
    g_sections: engineTags.filter(t => t === 'G').length,
    both_sections: engineTags.filter(t => t === 'ОБА').length,
    qc_score: brief.qc_score
  };
});

return [{ json: { ...d, ml_features: features }}];

// === Update ML Scores in NocoDB ===
const qcData = $('Quality Gate v2').first().json;
let structScore = null, contentScore = null;

try { structScore = $('ML Structure Rank').first().json.score || null; } catch(e) {}
try { contentScore = $('ML Content Quality').first().json.score || null; } catch(e) {}

if (!structScore && !contentScore) {
  return [{ json: { ...qcData, ml_structure_score: null, ml_content_score: null, ml_updated: false }}];
}

// Обновляем каждую запись в NocoDB с ML-скорами
const updates = qcData.nocodb_payload.map((brief, idx) => ({
  page_slug: brief.page_slug,
  project_id: brief.project_id,
  ml_structure_score: structScore,
  ml_content_score: contentScore
}));

return [{ json: {
  ...qcData,
  ml_structure_score: structScore,
  ml_content_score: contentScore,
  ml_updates: updates,
  ml_updated: true
}}];

// === Log Success v4.0 ===
const batch = $('Quality Gate v2').first().json;
const mlData = $('Merge ML Scores').first().json;

console.log(`[Step08 v4.0] ✓ Batch ${batch.batch_index}/${batch.total_batches}: ${batch.briefs_count} briefs | QC: PASS (${batch.qc_avg_score}/100) | ML Structure: ${mlData.ml_structure_score ?? 'N/A'} | ML Content: ${mlData.ml_content_score ?? 'N/A'} | LLM: ${batch.llm_source} | Tokens: ${batch.groq_tokens}`);

return [{ json: {
  batch_index: batch.batch_index,
  total_batches: batch.total_batches,
  briefs_count: batch.briefs_count,
  qc_passed: true,
  qc_avg_score: batch.qc_avg_score,
  ml_structure_score: mlData.ml_structure_score,
  ml_content_score: mlData.ml_content_score,
  llm_source: batch.llm_source
}}];

// === Log QC Failure ===
const batch = $('Quality Gate v2').first().json;

console.warn(`[Step08 v4.0] ✗ Batch ${batch.batch_index}/${batch.total_batches}: QC FAIL (${batch.qc_avg_score}/100) | Critical: ${batch.qc_critical_count} | Issues: ${batch.qc_issues?.length || 0} | LLM: ${batch.llm_source}`);
if (batch.qc_issues?.length > 0) console.warn('  Issues: ' + batch.qc_issues.join('; '));

return [{ json: {
  batch_index: batch.batch_index,
  total_batches: batch.total_batches,
  briefs_count: batch.briefs_count,
  qc_passed: false,
  qc_avg_score: batch.qc_avg_score,
  qc_issues: batch.qc_issues,
  llm_source: batch.llm_source
}}];

// === Build Response v4.0 ===
// Добавлено: attribution baseline, ML агрегация, Content Quality Stack summary

const response = $input.first().json;
const validate = $('Validate & Sanitize v4').first().json;
const ragInfo = $('Merge RAG Context v2').first().json;
const rows = response.list || [];

const totalWords = rows.reduce((s,r) => s + (r.word_count_target||0), 0);
const totalCTA = rows.reduce((s,r) => s + (r.cta_blocks||0), 0);
let totalSections = 0;
let totalQC = 0;
const priorityCounts = { high: 0, medium: 0, low: 0 };
const schemaAll = new Set();

rows.forEach(r => {
  try {
    const sec = typeof r.sections_json === 'string' ? JSON.parse(r.sections_json) : (r.sections_json || []);
    totalSections += sec.length;
  } catch(e) {}
  priorityCounts[r.implementation_priority || 'medium']++;
  totalQC += (r.qc_score || 0);
  try {
    const schemas = JSON.parse(r.schema_types || '[]');
    schemas.forEach(s => schemaAll.add(s));
  } catch(e) {}
});

const avgQC = Math.round(totalQC / Math.max(rows.length, 1));

return [{ json: {
  status: 'success',
  step: '08_page_briefs',
